import sys

def main():
    lines = sys.stdin.read().split("\n")
    idx = 0
    n = int(lines[idx].strip()); idx += 1
    entered = []
    for _ in range(n):
        entered.append(lines[idx].strip()); idx += 1
    m = int(lines[idx].strip()); idx += 1
    returned = []
    for _ in range(m):
        returned.append(lines[idx].strip()); idx += 1
    # 입장 명단에서 귀환 명단을 한 번씩 차감하고 남은 인원을 사전순으로 정렬한다
    cnt = {}
    for name in entered:
        cnt[name] = cnt.get(name, 0) + 1
    for name in returned:
        cnt[name] -= 1
    missing = []
    for name, c in cnt.items():
        for _ in range(c):
            missing.append(name)
    missing.sort()
    print(" ".join(missing))

if __name__ == "__main__":
    main()

