        cnt[l] -= 1
    for i in range(1, n + 1):
        if cnt[i] != 0:
            continue
        if i - 1 >= 1 and cnt[i - 1] == 2:
            cnt[i - 1] -= 1
            cnt[i] += 1
    count = 0
    for i in range(1, n + 1):
        if cnt[i] >= 1:
            count += 1
    print(count)

