import sys


def main():
    data = sys.stdin.read().split("\n")
    n = int(data[0])
    g = []
    for i in range(n):
        g.append(list(map(int, data[1 + i].split())))
    parent = list(range(n))

    def find(x):
        # 경로 압축(반복형)
        root = x
        while parent[root] != root:
            root = parent[root]
        while parent[x] != root:
            parent[x], x = root, parent[x]
        return root

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb

    for i in range(n):
        for j in range(n):
            if g[i][j] == 1:
                union(i, j)
    # 루트 개수 = 동맹 세력 수
    count = sum(1 for i in range(n) if find(i) == i)
    print(count)

if __name__ == "__main__":
    main()

import sys


def main():
    data = sys.stdin.read().split("\n")
    idx = 0
    f = data[idx].split(); idx += 1
    n, W = int(f[0]), int(f[1])
    items = []
    for _ in range(n):
        t = data[idx].split(); idx += 1
        items.append((int(t[0]), int(t[1])))
    # 0/1 배낭 DP. dp[j] 는 용량 j 까지 담을 수 있는 최대 가치.
    dp = [0] * (W + 1)
    for w, v in items:
        # 용량을 큰 쪽부터 갱신해 한 물품이 한 번만 쓰이게 한다.
        for j in range(W, w - 1, -1):
            if dp[j - w] + v > dp[j]:
                dp[j] = dp[j - w] + v
    print(dp[W])

if __name__ == "__main__":
    main()

