def main():
    data = sys.stdin.read().split("\n")
    s = data[0]
    # 각 문자의 마지막 등장 위치, 미등장은 -1
    last = {}
    left = 0
    best = 0
    for i, ch in enumerate(s):
        # 같은 문자가 창 안에 있으면 왼쪽 경계를 그 다음으로 이동
        if ch in last and last[ch] >= left:
            left = last[ch] + 1
        last[ch] = i
        if i - left + 1 > best:
            best = i - left + 1
    print(best)

