import sys


def main():
    data = sys.stdin.read().split("\n")
    n, m = map(int, data[0].split())
    edges = []
    for e in range(m):
        u, v, w = map(int, data[1 + e].split())
        edges.append((u, v, w))
    INF = float("inf")
    # 거리 표 초기화. 자기 자신은 0, 나머지는 INF
    d = [[0 if i == j else INF for j in range(n + 1)] for i in range(n + 1)]
    for u, v, w in edges:
        if w < d[u][v]:
            d[u][v] = w
    # 플로이드 워셜
    for k in range(1, n + 1):
        dk = d[k]
        for i in range(1, n + 1):
            dik = d[i][k]
            if dik == INF:
                continue
            di = d[i]
            for j in range(1, n + 1):
                nd = dik + dk[j]
                if nd < di[j]:
                    di[j] = nd
    out = []
    for i in range(1, n + 1):
        row = []
        for j in range(1, n + 1):
            row.append("-1" if d[i][j] == INF else str(d[i][j]))
        out.append(" ".join(row))
    print("\n".join(out))

if __name__ == "__main__":
    main()

import sys


def main():
    data = sys.stdin.read().split("\n")
    n, m, k = map(int, data[0].split())
    reports = []
    for i in range(m):
        a, b = map(int, data[1 + i].split())
        reports.append((a, b))
    seen = set()
    # by[b] = b를 신고한 사람들의 집합
    by = {}
    for a, b in reports:
        key = (a, b)
        if key not in seen:
            seen.add(key)
            by.setdefault(b, set()).add(a)
    mail = [0] * (n + 1)
    for b, reporters in by.items():
        if len(reporters) >= k:
            for a in reporters:
                mail[a] += 1
    print(" ".join(str(mail[i]) for i in range(1, n + 1)))

if __name__ == "__main__":
    main()

